// Detect WAHA Session from webhook or trigger
// Maps webhookId to session name for routing
// UPDATED: Correct session mapping per user requirements

const input = $input.item.json || {};

// WAHA webhook IDs mapped to sessions
// User setup:
// - default: Personal use (4695885133)
// - default-rensto: Rensto business
// - wonder: Customers/prospects
// - golden-art-photography: Golden Art Photography (Marianna)
const webhookToSession = {
  '7512b576-dadc-4f19-a5d9-baaf4cb165ef': 'default',                    // Shai Voice Agent (personal)
  '556f1aab-220c-4281-90b8-0570465d50b1': 'default-rensto',             // Router workflow (Rensto business)
  'f030f271-8ca6-46f1-816b-23305205516c': 'wonder',                     // Wonder.Care workflow (customers)
  'b708555b-e1ab-4bb4-bbca-452633d3aa54': 'golden-art-photography'      // Golden Art Photography (Marianna)
};

// Try to get webhookId from various sources
let webhookId = input.webhookId || input.webhook?.id || '';

// If not found, try to get from WAHA trigger metadata
if (!webhookId && input.payload) {
  // Check if there's session info in payload
  webhookId = input.payload.session || input.payload.webhookId || '';
}

// Detect session from webhookId
let detectedSession = 'default-rensto'; // Default fallback for this workflow
if (webhookId && webhookToSession[webhookId]) {
  detectedSession = webhookToSession[webhookId];
}

console.log('[Session Detector] WebhookId:', webhookId);
console.log('[Session Detector] Detected Session:', detectedSession);

// Store session in static data for downstream nodes
let staticData;
try {
  staticData = this.getWorkflowStaticData('global');
} catch (e) {
  staticData = {};
}

staticData.currentWahaSession = detectedSession;

try {
  this.setWorkflowStaticData('global', staticData);
} catch (e) {
  console.log('[Session Detector] Could not save static data');
}

return [{
  json: {
    ...input,
    wahaSession: detectedSession,
    webhookId: webhookId
  }
}]

const query = $json.input || 'general inquiry';
const response = await fetch('http://172.245.56.50:8020/query', {
  method: 'POST',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({ query: query, mode: 'mix' })
});
return (await response.json()).response || 'No info found.';

